var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"옥상에 직접 착륙하는 건 너무 위험해!","JPN":"屋上に直接着陸するのは危険すぎるわ！","ENG":"It's too dangerous to directly land on the rooftop!","TWN":"直接降落在頂樓風險太大！"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"오지만디아스의 사정거리에 닿으면 바로 격추 판정이 날 거야!","JPN":"オジマンディアスの射程距離内に入ったら、すぐに撃墜判定を食らうはずよ！","ENG":"The ship will be shot down as soon as we enter Ozymandias' range!","TWN":"若是進到奧茲曼迪亞斯的射程範圍內，就會立刻被判定為擊落！"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"내가 데려다 줄 수 있는 건, 작전대로 87층 사무 구역!","JPN":"私が連れていけるのは、作戦通り87階のオフィスエリアまで！","ENG":"The closest I can do is the 87th floor office area like we planned!","TWN":"按照作戰計畫，我就只能帶你們到87樓的辦公區！"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"그 위로 옥상까지는 너희 셋이 돌파해야 해!","JPN":"そこから屋上までは、あなたたち三人で突破するしかない！","ENG":"You three will have to go up to the rooftop yourselves from there!","TWN":"從那裡到頂樓，就需要你們三個人一起突破！"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"알고 있어요!","JPN":"わかっています！","ENG":"I know that!","TWN":"我知道！"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L10_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"생각보다 돌파가 너무 순조로운데. 지하 루트에서도 별다른 연락이 없어.","JPN":"思ったより突破が順調すぎるな。地下ルートからもこれといった連絡がない。","ENG":"This is going way smoother than I thought. Plus, nothing out of the ordinary from the underground team too.","TWN":"好像比我想像得還要順利，地下路線也沒有收到特別的通知。"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L11_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"이거 함정 같은데 괜찮겠냐, 꼬맹이?","JPN":"これは罠っぽいな。大丈夫なのか、おこちゃま？","ENG":"This feels like a trap. You sure about this, kid?","TWN":"感覺好像是陷阱，沒關係嗎，小鬼？"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L12_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"아마도 한꺼번에 모아서 리타이어 시키려고 일부러 길을 내준 거겠죠.","JPN":"おそらく一か所に集めて一気にリタイアさせるために、わざと道を開けているのよ。","ENG":"I'm sure she let us in on purpose in order to gather us all in one place and take us down all at once.","TWN":"他們應該是刻意把我們聚在一處，再把我們全都一起淘汰。"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L13_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"상관없어요. 결국, 그 잘난 맛에 사는 버릇이 발목을 잡을 테니까.","JPN":"関係ないわ。結局その傲慢さに足元を掬われることになるんだから。","ENG":"But it doesn't matter. Because in the end, her cockiness is what will bite her in the butt.","TWN":"無所謂，她最後還是會嚐到聰明反被聰明誤的滋味。"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L15_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"거의 도착했어, 얘들아! 외벽 강화 유리를 깨고 사무 구역으로 진입할 거야!","JPN":"もうすぐ着くよ、みんな！　外壁の強化ガラスを割ってオフィスエリアに侵入するわよ！","ENG":"We're almost there, guys! We're going to break the tempered glass and enter the office space!","TWN":"就快到了！接下來破壞外牆的強化玻璃進到辦公區！"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L18_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"건물에 돌입하자마자, 총탄이 쏟아질 거예요!","JPN":"ビルに突入した途端、銃弾が降り注ぐと思います！","ENG":"Once we're in, bullets are going to fly everywhere!","TWN":"一進到大樓就會有子彈掃射過來！"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L19_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"제가 먼저 내려서 방패로 길을 열게요. 엄호 부탁해요.","JPN":"私が先に降りて盾で道を作ります。援護をお願いします。","ENG":"I'll get off first and open the way with my shield. Cover me.","TWN":"我先下去用盾牌開路，你們掩護我。"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"알겠어요! 저 열심히 할게요!","JPN":"わかりました！　私頑張ります！","ENG":"Okay! I'll do my best!","TWN":"好！我會加油的！"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"좋아, 이제야 본격적인 시작이구만.","JPN":"よし、ここからが本番だな。","ENG":"All right. The party's just about to start for real.","TWN":"很好，比賽現在才開始。"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"다들 꽉 잡아!! 간다아아아아!!","JPN":"みんなしっかり掴まって！！　行くよ！！","ENG":"Hang tight!! Here goes nothing!!","TWN":"大家抓緊！！衝啊～～～！！"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"RIFLE_CHARADE_NULL_NULL","text":{"KOREA":"침입자다!! 침입자가 건물 외벽을 뚫고 진입했다!","JPN":"侵入者だ！！　侵入者がビルの外壁を突破してきたぞ！","ENG":"Intruders!! Intruders entered the building by breaking through the exterior wall!","TWN":"有入侵者！！入侵者衝破大樓外牆進來了！"},"stage":{"bg":"OFFICE_MESSED","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"RIFLE_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L30_1","type":"dialog","speaker":"RIFLE_CHARADE_NULL_NULL","text":{"KOREA":"어서 막아!! 옥상에 지원을 불러!!","JPN":"早く行く手を阻め！！　屋上に応援を呼ぶんだ！","ENG":"Stop them!! Call reinforcements from the rooftop!!","TWN":"快擋住！！向頂樓請求支援！！"},"stage":{"bg":"OFFICE_MESSED","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L35_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"지금이에요!! 모두 돌입하세요!!","JPN":"今です！！　みんな突入してください！！","ENG":"Now! Everyone, charge!!","TWN":"就是現在！！大家快衝！！"},"stage":{"bg":"OFFICE_MESSED","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L42_1","type":"dialog","speaker":"RIFLE_ADMIN_NULL_NULL","text":{"KOREA":"녀석들의 본대가 항공 루트로 진입했다는 연락을 받았다.","JPN":"奴らの本隊が航空ルートから侵入してきたとの連絡があった。","ENG":"According to reports, their main squad has breached the building by aerial route.","TWN":"收到消息，對方的主力選手已經從空中路線進入大樓。"},"stage":{"bg":"BASEMENT","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L43_1","type":"dialog","speaker":"RIFLE_ADMIN_NULL_NULL","text":{"KOREA":"여기 있는 녀석들은 양동을 위한 미끼라는 뜻이겠지.","JPN":"ここにいる連中は陽動作戦のためのおとりというわけだな。","ENG":"This means that the ones down here are just bait.","TWN":"意思就是這裡的人只是轉移眼目的誘餌。"},"stage":{"bg":"BASEMENT","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"RIFLE_ADMIN_NULL_NULL","text":{"KOREA":"챔피언의 메시지다. 녀석들이 본대와 합류하지 못하도록 제압해.","JPN":"チャンピオンからのメッセージだ。こいつらが本隊と合流できないように制圧しろ。","ENG":"A message from the champion. \\"Make sure to stop them from joining with the main squad.\\"","TWN":"冠軍說，制服這些傢伙，讓他們不能和主力選手會合。"},"stage":{"bg":"BASEMENT","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"쳇, 아까보다 공격이 거세졌어. 아무래도 우리 작전을 눈치 챈 모양인데?","JPN":"ちっ、さっきより攻撃が激しくなりやがった。どうやら俺たちの作戦に気づいたみたいだぞ？","ENG":"Tch. Their attacks are getting stronger. Guess they've figured out our plan, huh?","TWN":"嘖，攻勢變猛烈了，似乎是發現我們真正的目的了。"},"stage":{"bg":"BASEMENT","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"꼬마 대장한테는 아직 연락이 없어. 이제 어떡할래?","JPN":"チビ隊長からはまだ連絡がない。これからどうする？","ENG":"We still have no word from Little Captain. What do you want to do now?","TWN":"小不點隊長還沒消息，現在該怎麼辦？"},"stage":{"bg":"BASEMENT","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"이 정도면, 충분히 시간을 벌었겠죠.","JPN":"もう十分に時間は稼いだと思います。","ENG":"I think we've bought them enough time.","TWN":"我們目前應該有爭取到足夠的時間。"},"stage":{"bg":"BASEMENT","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"로이 씨는 먼저 지상으로 올라가서 펠리세트 씨와 합류하세요.","JPN":"ロイさんは先に地上に上がってフェリセットさんたちと合流してください。","ENG":"Roy, you head up and join Félicette first.","TWN":"羅伊，你先上去和費莉塞特會合。"},"stage":{"bg":"BASEMENT","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"저는 이곳에 남아서 최대한 적의 발을 묶겠습니다.","JPN":"私はここに残ってできるだけ敵を足止めしておきます。","ENG":"I'll stay down here and try my best to keep them busy.","TWN":"我留在這裡擋住他們。"},"stage":{"bg":"BASEMENT","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L6_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"혼자서 괜찮겠어? 저 녀석들 보통내기가 아니라고.","JPN":"一人で大丈夫なのか？　あいつらなかなかの手練れだぞ。","ENG":"Are you certain you'll be fine by yourself? Those jerks aren't your average tossers.","TWN":"你自己沒問題嗎？那些傢伙可不是省油的燈。"},"stage":{"bg":"BASEMENT","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L7_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"상관없어요. 농성은 제 특기니까요.","JPN":"大丈夫です。籠城は私の得意分野ですから。","ENG":"I'll be fine. Sieges are my specialty.","TWN":"沒問題，我很擅長防守。"},"stage":{"bg":"BASEMENT","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"적이 아무리 많다고 해도, 이렇게 복잡한 통로에서의 게릴라전은 제가 유리해요.","JPN":"敵がいくら多くても、このような複雑な通路でのゲリラ戦は、私に有利です。","ENG":"No matter how outnumbered I am, I have the upper hand in guerrilla warfare in these kinds of complicated aisles.","TWN":"雖然敵人很多，但在格局這麼複雜的通道裡進行遊擊戰，反而對我有利。"},"stage":{"bg":"BASEMENT","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"준비해둔 비살상 트랩을 다 소모하기 전까지는 시간을 벌 수 있을 겁니다.","JPN":"用意しておいた非殺傷トラップを使い切るまでは時間を稼げるはずです。","ENG":"I'll be able to delay them until I run out of the non-lethal traps I've set up.","TWN":"在我準備好的那些不具殺傷力的陷阱消耗殆盡之前，應該是可以爭取到一點時間。"},"stage":{"bg":"BASEMENT","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"어차피 제압당한다고 해도, 분풀이로 몇 대 얻어맞는 정도겠죠.","JPN":"どうせ制圧されても、腹いせに何発か殴られるだけでしょう。","ENG":"Even if they catch me, they won't be able to do much more than just beat me a few times out of anger.","TWN":"就算被逮到，頂多就是被打一頓洩憤。"},"stage":{"bg":"BASEMENT","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L11_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"야, 그런 식으로 말하면 더 왠지 꺼림칙하잖아.","JPN":"おい、そんな言い方されると逆に後味悪くて行けないだろ。","ENG":"Hey, putting it like that makes me feel even more uneasy.","TWN":"喂，你這樣說反而讓我心裡很不安。"},"stage":{"bg":"BASEMENT","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L14_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"서두르세요, 로이 씨!","JPN":"急いでください、ロイさん！","ENG":"Hurry, Roy!","TWN":"動作快，羅伊！"},"stage":{"bg":"BASEMENT","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"나 참. 알았다고. 이래서 건틀렛은 마음에 안 든다니까.","JPN":"ったく。わかったよ。これだからガントレットは気に入らねえ。","ENG":"Blimey. Fine, I'll go. This is why I don't like the Gauntlet.","TWN":"真是的，好啦，所以我才很討厭聖鎧的嘛。"},"stage":{"bg":"BASEMENT","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"거의 다왔어요. 이제 옥상이에요!","JPN":"あともう少しです。屋上はすぐそこです！","ENG":"We're almost at the top!","TWN":"就快到頂樓了！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"이 앞에 오지만디아스가 기다리고 있을 거예요.","JPN":"この先にオジマンディアスが待っているはずです。","ENG":"Beyond that door, Ozymandias is waiting for us.","TWN":"奧茲曼迪亞斯應該就在前面等著。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"조심해, 아무 생각 없이 열었다간 바로 리타이어 당할 수도 있어.","JPN":"気をつけろ。無闇にドアを開けたら一瞬でリタイヤになる可能性もある。","ENG":"Be careful. Open it without thinking and you'll be taken down instantly.","TWN":"小心，不要一下就打開，否則很有可能會馬上遭到淘汰。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"아래층에서 발소리가…! 저희를 쫓아오나 봐요!","JPN":"下から足音が……！　私たちを追いかけてくるみたいです！","ENG":"I hear footsteps coming from below...! I think they're chasing us!","TWN":"樓下有腳步聲……！好像有人追上來了！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"쳇, 주인은 망나닌데 기르는 개들은 성실하네.","JPN":"ちっ、主人はあんなんなのに、飼い犬たちは忠実だな。","ENG":"Tch! So diligent, for dogs whose owner is a butt wipe.","TWN":"嘖，主人是個混蛋，但養的狗倒是很忠心嘛。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"그럼 열게요. 하나… 둘….","JPN":"では開けます。せーの……","ENG":"Then I'll open it. One... Two...","TWN":"那我打開了。1……2……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"어서 와, 병아리들.","JPN":"いらっしゃい。ヒヨコたち。","ENG":"Welcome, little chicks.","TWN":"各位菜鳥你們好～"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L29_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"여기까지 오느라고 고생 많았어.","JPN":"ここまでお疲れ様。","ENG":"Congrats on making it all the way up here.","TWN":"要上到頂樓很辛苦吧？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"인사도 안 하고 다짜고짜 쏘기야? 아직 쇼맨십이 부족하네.","JPN":"挨拶もなしでいきなり撃ってくるなんて、まだまだショーマンシップが足りないわね。","ENG":"You're just shooting at me without saying hi? You do lack showmanship, don't you?","TWN":"都不打聲招呼就直接開槍嗎？說好的節目效果呢？"},"stage":{"bg":"GAUNTLET","bgm":"BATTLE_PVP_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"라이카, 노엘 간격을 넓혀요. 무슨 짓을 할지 몰라요.","JPN":"ライカ、ノエル、距離をとってください。何をしてくるかわかりません。","ENG":"Laika, Noelle, spread out. We don't know what she'll do.","TWN":"萊卡、洛艾兒，拉開距離。不知道她會做出什麼事。"},"stage":{"bg":"GAUNTLET","bgm":"BATTLE_PVP_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L40_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"그렇게 안달하지 않아도 돼. 정상에서 기다린다고 했잖아.","JPN":"そんなに焦らなくていいわよ。頂上で待ってるって言ったじゃない。","ENG":"You don't have to be so anxious. I said that I'd wait for you at the top, didn't I?","TWN":"不用緊張，我說過我會在頂樓等你。"},"stage":{"bg":"GAUNTLET","bgm":"BATTLE_PVP_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"GAUNTLET","bgm":"BATTLE_PVP_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"그나저나, 조금 아쉽네.","JPN":"でも、少し残念ね。","ENG":"But, you know, I'm a little disappointed.","TWN":"不過，有點可惜。"},"stage":{"bg":"GAUNTLET","bgm":"BATTLE_PVP_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"하도 큰 소리 치길래. 마지막에는 그 유미나라는 애가 나올 줄 알았거든.","JPN":"あんなに大口を叩いていたから、ヤナギ・ミナって子が最後に出てくるのかと思っていたのに。","ENG":"You went on and on about beating me, so I was expecting that Yoo Mina girl to show up in the finals.","TWN":"之前那樣誇下海口，我還以為那個叫劉米娜的人會在最後一刻出現呢。"},"stage":{"bg":"GAUNTLET","bgm":"BATTLE_PVP_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"그래야 나랑 급이 좀 맞지 않겠어?","JPN":"それでやっと勝負になるというものじゃない？","ENG":"Or else, how would you match my skill level?","TWN":"這樣才符合我的水準吧？"},"stage":{"bg":"GAUNTLET","bgm":"BATTLE_PVP_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L48_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"시끄러워요. 오지만디아스.","JPN":"黙ってください。オジマンディアス。","ENG":"Shut it, Ozymandias.","TWN":"你閉嘴，奧茲曼迪亞斯。"},"stage":{"bg":"GAUNTLET","bgm":"BATTLE_PVP_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L49_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"이건 나랑 당신 싸움이에요. 유미나 씨와는 관계없어.","JPN":"これは私とあなたとの戦いです。ミナさんは関係ありません。","ENG":"This fight is about you and me. Yoo Mina has nothing to do with it.","TWN":"這是我和你之間的事，與劉米娜無關。"},"stage":{"bg":"GAUNTLET","bgm":"BATTLE_PVP_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L5_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"맞아요! 미나 선배는 당신 같이 비겁한 챔피언보다 훨씬 강하다고요! 메롱!","JPN":"そうです！　ミナ先輩はあなたのような卑怯なチャンピオンよりずっと強いんですよ！　べーっ！","ENG":"She's right! Mina is way stronger than some cowardly champion like you! Bleh!","TWN":"沒錯！你這個手段骯髒的冠軍，米娜前輩比你強多了！ㄌㄩㄝ～"},"stage":{"bg":"GAUNTLET","bgm":"BATTLE_PVP_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L7_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"후후, 그 말을 들으니 더 관심이 생기는데.","JPN":"ふふ、そう言われるともっと興味が湧いてくるわ。","ENG":"Fu fuu. Well, that makes me even more interested in her.","TWN":"呵呵，聽你那麼說，反而讓我更感興趣呢。"},"stage":{"bg":"GAUNTLET","bgm":"BATTLE_PVP_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"그래서? 그 애 없이 너희 셋이서 나를 쓰러트릴 수 있다고 생각해?","JPN":"それで？　あの子なしにあなたたち三人だけで私を倒せるの？","ENG":"So? Do you really think you three can defeat me?","TWN":"所以，你們三個覺得可以不靠她就打敗我嗎？"},"stage":{"bg":"GAUNTLET","bgm":"BATTLE_PVP_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"GAUNTLET","bgm":"BATTLE_PVP_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"뭐, 좋아. 어차피 실력 차이야 금방 깨달을 테니까.","JPN":"まぁ、いいわ。どうせすぐに実力の差を知ることになるもの。","ENG":"All right. But I'm sure you'll notice the difference in power soon enough.","TWN":"好吧，反正你們馬上就能感受到實力的落差。"},"stage":{"bg":"GAUNTLET","bgm":"BATTLE_PVP_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L12_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"너무 일찍 포기하지만 말라구?","JPN":"でもあんまりあっけなく諦めたりしないでよね？","ENG":"Just don't give up so quickly, okay?","TWN":"千萬不要太早放棄噢？"},"stage":{"bg":"GAUNTLET","bgm":"BATTLE_PVP_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};